-- 0013: 移除明志科大（education）、更新 Advisor/競賽選手 經歷（本人 admin 版）、FRC 出賽 3→2

INSERT OR REPLACE INTO sections (key, zh, en, updated_at) VALUES ('education', '[{"school": "元智大學", "degree": "電機工程學系學士", "period": "2024.09 – 2027.09"}, {"school": "南港高工", "degree": "電子科", "period": "2020.09 – 2023.06"}]', '[{"school": "Yuan Ze University", "degree": "B.S. Electrical Engineering", "period": "2024.09 – 2027.09"}, {"school": "Nangang Vocational H.S.", "degree": "Electronics Program", "period": "2020.09 – 2023.06"}]', datetime('now'));
INSERT OR REPLACE INTO sections (key, zh, en, updated_at) VALUES ('experience', '[{"role": "實驗室專題生", "organization": "元智大學 林書彥教授實驗室", "period": "2025.05 – 現在", "description": "主導 ICU VAP 早期預警研究：設計 Stay-Level 5-Fold 交叉驗證消除公開基準中的 Patient-Level Data Leakage，以 Integrated Gradients 特徵歸因縮減至 4 項非侵入指標，LSTM 達 72h AUROC 0.98–0.99。論文投稿 IEEE GCCE 2026。"}, {"role": "Engineering Advisor & Systems Integrator", "organization": "FRC TEAM 7645", "period": "2023 – 現在", "description": "2023 年起持續擔任 Engineering Advisor。\n過往:\n負責機器人系統架構：多感測器融合、PID 馬達閉迴路控制調校與軟硬體介面定義，現因系統汰換而轉為營運指導。\n現在:\n引入 LLM 輔助工具，把原本反覆試錯的韌體除錯流程縮短約一週，並把這套除錯思路教給後進，讓他們能從根因分析切入而非逐行亂試。順帶幫團隊重做了官網，減少公關端要重複回覆的問題。"}, {"role": "競賽選手", "organization": "南港高工 NK-MTC 7645", "period": "2020.06 – 2023.09", "description": "團隊裡的萬金油角色，作為機械、程式、電路以及公關中間的橋樑維繫。3 年內出賽2 場 FRC 國際區域賽（含 2020 中科 5G 區域賽、2022 台灣鴻海區域賽），並參加全國技能競賽 集體創作職種、全國高級中等學校技藝競賽 數位電子。"}]', '[{"role": "Research Intern", "organization": "Yuan Ze Univ. — Prof. Lin Shu-Yan''s Lab", "period": "2025.05 – Present", "description": "Leading ICU VAP early-warning research: designed Stay-Level 5-Fold CV to eliminate patient-level data leakage in public baselines, and used Integrated Gradients to distill 14 features to 4 non-invasive metrics; LSTM achieves 72h AUROC 0.98–0.99. Paper submitted to IEEE GCCE 2026."}, {"role": "Engineering Advisor & Systems Integrator", "organization": "FRC TEAM 7645", "period": "2023 – Present", "description": "Engineering Advisor since 2023.\nPreviously:\nOwned robot systems architecture — multi-sensor fusion, PID closed-loop motor control tuning, and hardware/software interface definition; shifted to an operational advisory role as that system was retired.\nNow:\nIntroduced LLM-assisted tools that cut the trial-and-error firmware debugging cycle by about a week, and coach newer members to debug from root cause instead of line-by-line guessing. Also rebuilt the team website to cut repetitive PR inquiries.", "frc": true}, {"role": "Competitive Athlete", "organization": "Nangang VHS NK-MTC 7645", "period": "2020.06 – 2023.09", "description": "The team''s utility player — the bridge between mechanical, software, electrical, and PR. Competed in 2 FRC international regional events over 3 years (2020 CSIA 5G Regional and 2022 Taiwan Foxconn Regional), and took part in the National Skills Competition (Team Project category) and the National Vocational High School Craft Competition (Digital Electronics)."}]', datetime('now'));
